frappe.ui.form.on('Journal Entry', {
	refresh(frm) {
		// your code here
	}
})

frappe.ui.form.on('Journal Entry Account', {
    party: function(frm, cdt, cdn) {
        var d = frappe.get_doc(cdt, cdn);

        if (!d.account && d.party_type && d.party && (d.party_type === 'Receivable' || d.party_type === 'Payable' )) {
            frappe.db.get_value(d.party_type , d.party, 'account', (r) => {
                if(r && r.account) {
                    // نملأ حقل الحساب في السطر الحالي
                    // frappe.model.set_value(cdt, cdn, 'account', r.account);
                    // frappe.model.set_value(cdt, cdn, 'party_type', d.party_type);
                    d.account=r.account;
                    frm.refresh_field('accounts');
                }
            });
        }
    }
});

frappe.ui.form.on('Payment Entry', {
    party: function(frm) {
        if((frm.doc.party_type === 'Receivable' ) && frm.doc.party) {
            frappe.db.get_value('Receivable', frm.doc.party, 'account', (r) => {
                if(r && r.account) {
                    if(frm.doc.payment_type === 'Pay') {
                        frm.set_value('paid_to', r.account);
                    } else if(frm.doc.payment_type === 'Receive') {
                        frm.set_value('paid_from', r.account);
                    }
                }
            });
        }
        if(( frm.doc.party_type === 'Payable' ) && frm.doc.party) {
            frappe.db.get_value('Payable', frm.doc.party, 'account', (r) => {
                if(r && r.account) {
                    if(frm.doc.payment_type === 'Pay') {
                        frm.set_value('paid_to', r.account);
                    } else if(frm.doc.payment_type === 'Receive') {
                        frm.set_value('paid_from', r.account);
                    }
                }
            });
        }
    },
    refresh(frm) {
        if (frm.doc.docstatus == 1) {
            frm.set_df_property('party_type', 'depends_on', '');
            frm.refresh_field('party_type');
           // frm.set_df_property('party_type', 'read_only', 1);
        }
    },

    paid_amount: function(frm) {
        update_received_amount(frm);
    },

    received_amount: function(frm) {
        update_paid_amount(frm);
    }
});

function update_received_amount(frm) {
    const rate = frm.doc.source_exchange_rate || 0;
    const trate = frm.doc.target_exchange_rate || 0;
    const paid = frm.doc.paid_amount || 0;
    const base_paid = frm.doc.base_paid_amount || 0;

    const base_received = rate * base_paid;

    var received = rate * paid;

    if(trate!=0){
        received = received / trate;
    }

    if(frm.doc.payment_type == "Pay"){
        if(frm.doc.received_amount !== received) {
            //frm.doc.received_amount = received;
            //frm.refresh_field('received_amount');
            frm.set_value("received_amount", received);
        }
    }
}



function update_paid_amount(frm) {
    const rate = frm.doc.target_exchange_rate || 0;
    const srate = frm.doc.source_exchange_rate || 0;
    const received = frm.doc.received_amount || 0;
    const base_received = frm.doc.base_received_amount || 0;

    var base_paid = rate * base_received ;
    var paid = rate * received ;
    if(srate!=0){
        paid = paid / srate;
        base_paid = paid * srate;
    }
    if(frm.doc.payment_type == "Receive"){
        if(frm.doc.paid_amount !== paid) {
            frm.set_value("paid_amount", paid);
            //frm.doc.paid_amount = paid;
            //frm.refresh_field('paid_amount');
            //frm.set_value("base_paid_amount", base_paid);
        }
    }
}
